const savedLang = typeof localStorage !== 'undefined' ? localStorage.getItem('oficinapro_lang') : null

i18n.use(initReactI18next).init({
  resources,
  lng: savedLang || 'pt',
  fallbackLng: 'pt',
  interpolation: { escapeValue: false },
})

i18n.on('languageChanged', (lng) => {
  if (typeof localStorage !== 'undefined') localStorage.setItem('oficinapro_lang', lng)
  if (typeof document !== 'undefined') document.documentElement.lang = lng
})

export default i18n
